// Normalize all items into standard format
// Skip error items from continueOnFail nodes
const rawItems = $input.all().filter(i => !i.json.error && !i.json.errorMessage);
if (rawItems.length === 0) {
  return [{ json: { _skip: true, message: 'All sources returned errors' } }];
}
// RSS items have: title, link, contentSnippet, pubDate, creator
// HTML extracted items have: titles (array of strings)
const items = [];

for (const item of rawItems) {
  const d = item.json;

  // RSS items — have title + link
  if (d.title && d.link) {
    items.push({
      title: d.title,
      url: d.link,
      description: (d.contentSnippet || d.content || '').substring(0, 500),
      source: d.creator || d.feed?.title || 'RSS',
      date: d.pubDate || d.isoDate || new Date().toISOString(),
      category: 'news'
    });
  }

  // HTML extracted items — have titles array
  if (d.titles && Array.isArray(d.titles)) {
    for (const t of d.titles.slice(0, 15)) {
      const title = typeof t === 'string' ? t : (t.text || t);
      const href = typeof t === 'object' ? (t.href || t.link || '') : '';
      if (title && String(title).length > 5) {
        items.push({
          title: String(title).trim(),
          url: href || '',
          description: '',
          source: 'Scraping/BIP',
          date: new Date().toISOString(),
          category: 'local'
        });
      }
    }
  }
}

// Deduplicate within this batch by URL or title
const seen = new Set();
const unique = items.filter(item => {
  const key = item.url || item.title;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

if (unique.length === 0) {
  return [{ json: { _skip: true, message: 'No items found in any source' } }];
}

return unique.map(item => ({ json: item }));

// Check Qdrant for existing URLs — skip already-stored articles
const items = $input.all().map(i => i.json);

if (items.length === 1 && items[0]._skip) {
  return [{ json: { _skip: true, message: items[0].message } }];
}

const qdrantUrl = 'http://qdrant:6333';

let existingUrls = new Set();
try {
  const resp = await fetch(`${qdrantUrl}/collections/krasnik_news/points/scroll`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      limit: 1000,
      with_payload: true,
      filter: {}
    })
  });
  const data = await resp.json();
  if (data.result?.points) {
    for (const p of data.result.points) {
      if (p.payload?.url) existingUrls.add(p.payload.url);
      if (p.payload?.title) existingUrls.add(p.payload.title);
    }
  }
} catch (e) {
  // Collection might not exist yet — continue with all items
}

const newItems = items.filter(item => {
  return !existingUrls.has(item.url) && !existingUrls.has(item.title);
});

if (newItems.length === 0) {
  return [{ json: { _skip: true, message: 'No new articles (all already in Qdrant)' } }];
}

return newItems.map(item => ({ json: item }));

// Embed via Gemini gemini-embedding-001 + upsert to Qdrant
const items = $input.all().map(i => i.json);

if (items.length === 1 && items[0]._skip) {
  return [{ json: { status: 'skipped', message: items[0].message } }];
}

const qdrantUrl = 'http://qdrant:6333';
const geminiKey = $env.GEMINI_API_KEY || '';

if (!geminiKey) {
  return [{ json: { status: 'error', message: 'GEMINI_API_KEY not set' } }];
}

// Simple string hash for deterministic UUID (no crypto module needed)
function simpleHash(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1 >>> 16), 2246822507);
  h1 ^= Math.imul(h2 ^ (h2 >>> 13), 3266489909);
  h2 = Math.imul(h2 ^ (h2 >>> 16), 2246822507);
  h2 ^= Math.imul(h1 ^ (h1 >>> 13), 3266489909);
  const hex = (h2 >>> 0).toString(16).padStart(8, '0') + (h1 >>> 0).toString(16).padStart(8, '0');
  return hex.padEnd(32, '0');
}

function makeUuid(str) {
  const h = simpleHash(str);
  return `${h.slice(0,8)}-${h.slice(8,12)}-4${h.slice(13,16)}-a${h.slice(17,20)}-${h.slice(20,32)}`;
}

const points = [];
let embedded = 0;
let errors = 0;
let lastError = '';

for (const item of items) {
  try {
    const textToEmbed = `${item.title}. ${item.description || ''}`.substring(0, 2000);

    const embResp = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-embedding-001:embedContent?key=${geminiKey}`,
      headers: { 'Content-Type': 'application/json' },
      body: {
        model: 'models/gemini-embedding-001',
        content: { parts: [{ text: textToEmbed }] },
        outputDimensionality: 768
      },
      json: true
    });

    if (!embResp.embedding?.values) {
      errors++;
      lastError = 'No embedding: ' + JSON.stringify(embResp).substring(0, 200);
      continue;
    }

    const uuid = makeUuid(item.url || item.title);

    points.push({
      id: uuid,
      vector: embResp.embedding.values,
      payload: {
        title: item.title,
        url: item.url,
        description: item.description || '',
        source: item.source,
        date: item.date,
        category: item.category,
        collected_at: new Date().toISOString()
      }
    });
    embedded++;
    await new Promise(r => setTimeout(r, 150));
  } catch (e) {
    errors++;
    lastError = e.message || String(e);
  }
}

if (points.length > 0) {
  try {
    const upsertResp = await this.helpers.httpRequest({
      method: 'PUT',
      url: `${qdrantUrl}/collections/krasnik_news/points`,
      headers: { 'Content-Type': 'application/json' },
      body: { points },
      json: true
    });
    return [{ json: { status: 'ok', embedded, upserted: points.length, errors, lastError, qdrant: upsertResp.status || 'ok' } }];
  } catch (e) {
    return [{ json: { status: 'qdrant_error', message: e.message, embedded, lastError } }];
  }
}

return [{ json: { status: 'no_embeddings', embedded: 0, errors, lastError } }];

